CREATE OR REPLACE FUNCTION OFSERM.ABL_BANKING_GRT_EXPOSURE_DATA_CREATION(
    P_V_BATCH_ID         VARCHAR2,
    P_V_MIS_DATE         VARCHAR2,
    P_V_RUN_ID           VARCHAR2,
    P_V_PROCESS_ID       VARCHAR2,
    P_V_RUN_EXECUTION_ID VARCHAR2,
    P_N_RUN_SKEY         VARCHAR2,
    P_V_TASK_ID          VARCHAR2
) RETURN VARCHAR2 AUTHID CURRENT_USER AS

    ld_mis_date   DATE          := TO_DATE(P_V_MIS_DATE, 'YYYYMMDD');
    ln_mis_date   NUMBER        := TO_NUMBER(P_V_MIS_DATE);
    ln_run_skey   NUMBER(5)     := TO_NUMBER(SUBSTR(P_N_RUN_SKEY, 8, LENGTH(P_N_RUN_SKEY)));
    lv_run_id     VARCHAR2(64)  := SUBSTR(P_V_RUN_ID, 8, LENGTH(P_V_RUN_ID));

BEGIN

    insert /*+APPEND*/ into FSI_CAP_BANKING_EXPOSURES(N_COUNTRY_SKEY,N_MIS_DATE_SKEY,N_ACCT_SKEY,N_GAAP_SKEY,N_ISSUE_SKEY,F_FINANCIAL_ENTITY_IND,F_REGULATED_FIN_ENTITY_IND,N_CUST_SKEY,N_COUNTERPARTY_TYPE_SKEY,N_PROD_SKEY,N_REPAYMENT_TYPE_SKEY,F_INTERNAL_CUST_IND,N_COVERED_RWA_UL,N_CURR_12M_ECL,N_EL_AMOUNT,N_EXPOSURE_AMOUNT,N_EXP_COVERED_AMT,N_EXP_UNCOVERED_AMT,N_GROUP_ASSET_SIZE,N_LOSS_ALLOWANCE_LIFE_ECL,N_ORIGINAL_MATURITY,N_PRE_MITIGATION_RWA_EL,N_RESIDUAL_MATURITY,N_RUN_PARAMETER_SETUP_SKEY,N_RUN_SKEY,N_RWA_EL_AMT,N_RWA_UL_AMT,N_CUST_ANNUAL_SALES,N_SHAREHOLDING_PERCENT,N_UNCOVERED_RWA_UL,N_UNDRAWN_AMOUNT,V_APPROACH_TYPE,V_EXP_RCY_CODE,N_ENTITY_SKEY,N_REG_CAP_ACCT_PURPOSE_SKEY,F_CASH_POOL_DAILY_TRANSFER,F_CASH_POOL_LEGAL_ENFORCEABLE,F_CREDIT_IMPAIRMENT_FLAG,F_FINANCIAL_ASSET_IFRS9_FLAG,F_PREF_TREATMENT_FLAG,F_RW_BY_DISCRETION,N_CCF_OWN_ESTIMATE,N_EFF_MATURITY,N_EL_BEST_ESTIMATE_PERCENT,N_LGD_PERCENT_PRE_CRM,N_LONG_RUN_WEIGHTED_AVG_LGD,N_PD_PERCENT,N_PROVISION_AMOUNT,N_CAP_APPROACH_TYPE_SKEY,N_CAP_RECORD_TYPE_SKEY,V_RECORD_TYPE,N_BASEL_PARTY_GRADE_SKEY,N_STD_COUNTERPARTY_TYPE_SKEY,N_BASEL_PROD_TYPE_SKEY,N_SEC_POOL_SKEY,D_EXPOSURE_END_DATE,D_EXPOSURE_START_DATE,F_AUTO_CANCELLATION_FLAG,F_CORE_MKT_PARTICIPANT_FLAG,F_ELIGIBLE_PROTECTION_IND,F_EXP_DEFAULTED_FLAG,F_EXP_REV_FLAG,F_GUAR_BY_SOVERIGN_IND,F_SECURED_IND,F_SECURITIZED_FLAG,F_SENIOR_CLAIM_FLAG,F_UNCOND_CANCELLED_EXP_IND,N_EXP_LTV_RATIO,N_LOAD_RUN_ID,N_REMARGIN_FREQUENCY,N_RISK_WEIGHT,V_PRODUCT_BOOK_CODE,V_CCY_CODE)SELECT  /*+PARALLEL (4)*/ to_char(DIM_COUNTRY.N_COUNTRY_SKEY),to_char(DIM_DATES.N_DATE_SKEY),to_char(DIM_EXPOSURE.N_ACCT_SKEY),to_char(DIM_GAAP.N_GAAP_SKEY),to_char(DIM_ISSUE.N_ISSUE_SKEY),DIM_PARTY.F_FINANCIAL_ENTITY_IND,DIM_PARTY.F_REGULATED_FIN_ENTITY_IND,to_char(DIM_PARTY.N_PARTY_SKEY),to_char(DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY),to_char(DIM_PRODUCT.N_PROD_SKEY),to_char(DIM_REPAYMENT_TYPE.N_REPAYMENT_TYPE_SKEY),CASE  WHEN FCT_ENTITY_INFO_CUST.V_PARTY_ID IS NOT NULL  AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ('FLCS', 'PRCS','FAGR','PRAGR') THEN  'Y' ELSE 'N'   END,0,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_CURR_12M_ECL_STD END,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*(CASE WHEN STG_GUARANTEES.N_GUARANTEE_VALUE > 0 THEN STG_GUARANTEES.N_GUARANTEE_VALUE ELSE 0 END),0,0,FSI_CAP_PARTY_FINANCIALS.N_GROUP_ASSET_SIZE * B_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE IN ('NSAIRB','NSFIRB') THEN FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_IRB ELSE FSI_ACCT_MODELING_INFO.N_LOSS_ALLOWANCE_LIFE_ECL_STD END,DAYS_BETWEEN(STG_GUARANTEES.D_VALUE_DATE,STG_GUARANTEES.D_MATURITY_DATE,STG_GUARANTEES.V_DAY_COUNT_IND),0,DAYS_BETWEEN(STG_GUARANTEES.FIC_MIS_DATE,STG_GUARANTEES.D_MATURITY_DATE,STG_GUARANTEES.V_DAY_COUNT_IND),CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN RUN_PARAMETERS.N_RUN_PARAMETER_SETUP_SKEY ELSE NULL END,'870',0,0,FSI_CAP_PARTY_FINANCIALS.N_SALES_AMT* A_FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE,CASE WHEN DIM_BASEL_CAP_CONSL_APPR.v_basel_cap_consl_appr_code = 'PRCS' THEN FCT_ENTITY_INFO.n_shareholding_percent ELSE 1 END,0,FSI_CAP_CURRENCY_CONVERSION.N_EXCHANGE_RATE*STG_GUARANTEES.N_UNDRAWN_AMOUNT,CASE WHEN FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG ='N' THEN FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE ELSE NULL END,RUN_EXE_PARAMETERS_RCY.V_PARAM_VALUE_CODE,to_char(FCT_ENTITY_INFO.N_ENTITY_SKEY),to_char(FSI_ACCOUNT_PURPOSE_RECLASS.N_REG_CAP_ACCT_PURPOSE_SKEY),FSI_ACCT_MODELING_INFO.F_CASH_POOL_DAILY_TRANSFER,FSI_ACCT_MODELING_INFO.F_CASH_POOL_LEGAL_ENFORCEABLE,FSI_ACCT_MODELING_INFO.F_CREDIT_IMPAIRMENT_FLAG,FSI_ACCT_MODELING_INFO.F_FINANCIAL_ASSET_IFRS9_FLAG,FSI_ACCT_MODELING_INFO.F_PREF_TREATMENT_FLAG,FSI_ACCT_MODELING_INFO.F_RW_BY_DISCRETION,to_char(FSI_ACCT_MODELING_INFO.N_CCF_OWN_ESTIMATE),to_char(FSI_ACCT_MODELING_INFO.N_EFF_MATURITY),to_char(FSI_ACCT_MODELING_INFO.N_EL_BEST_ESTIMATE_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LGD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_LONG_RUN_WEIGHTED_AVG_LGD),to_char(FSI_ACCT_MODELING_INFO.N_PD_PERCENT),to_char(FSI_ACCT_MODELING_INFO.N_PROVISION_AMOUNT),to_char(FSI_CAP_APPROACH_TYPE_MASTER.N_CAP_APPROACH_TYPE_SKEY),to_char(FSI_CAP_RECORD_TYPE_MASTER.N_CAP_RECORD_TYPE_SKEY),FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE,to_char(FSI_PARTY_GRADE_RECLASS.N_BASEL_GRADE_SKEY),to_char(FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY),to_char(FSI_REG_PROD_TYPE_RECLASS.N_BASEL_PROD_TYPE_SKEY),to_char(SEC_POOL_MASTER.N_SEC_POOL_SKEY),STG_GUARANTEES.D_MATURITY_DATE,STG_GUARANTEES.D_VALUE_DATE,STG_GUARANTEES.F_AUTO_CANCELLATION_FLAG,STG_GUARANTEES.F_CORE_MKT_PARTICIPANT_FLAG,STG_GUARANTEES.F_ELIGIBLE_PROTECTION_IND,STG_GUARANTEES.F_EXP_DEFAULTED_FLAG,STG_GUARANTEES.F_EXP_REVOLVING_FLAG,STG_GUARANTEES.F_GUAR_BY_SOVERIGN_IND,STG_GUARANTEES.F_SECURED_IND,STG_GUARANTEES.F_SECURITIZED_FLAG,STG_GUARANTEES.F_SENIOR_CLAIM_FLAG,STG_GUARANTEES.F_UNCOND_CANCELLED_EXP_IND,to_char(STG_GUARANTEES.N_EXP_LTV_RATIO),to_char(STG_GUARANTEES.N_LOAD_RUN_ID),to_char(STG_GUARANTEES.N_REMARGIN_FREQUENCY),to_char(STG_GUARANTEES.N_RISK_WEIGHT),STG_GUARANTEES.V_BOOK_TYPE,STG_GUARANTEES.V_CCY_CODE FROM STG_GUARANTEES INNER JOIN DIM_DATES ON STG_GUARANTEES.fic_mis_date = DIM_DATES.d_calendar_date INNER JOIN DIM_RUN ON DIM_RUN.n_run_skey = '870' /*LEFT JOIN DIM_PRODUCT ON STG_GUARANTEES.V_PROD_CODE = DIM_PRODUCT.V_PROD_CODE*/ INNER JOIN DIM_EXPOSURE ON STG_GUARANTEES.V_CONTRACT_CODE = DIM_EXPOSURE.v_exposure_id AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_EXPOSURE.D_RECORD_START_DATE AND DIM_EXPOSURE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PARTY ON STG_GUARANTEES.v_cust_ref_code = DIM_PARTY.v_party_id AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_PARTY.D_RECORD_START_DATE AND DIM_PARTY.D_RECORD_END_DATE INNER JOIN DIM_PARTY_TYPE ON DIM_PARTY.V_PARTY_TYPE = DIM_PARTY_TYPE.V_PARTY_TYPE_CODE AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_PARTY_TYPE.D_RECORD_START_DATE AND DIM_PARTY_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN DIM_PRODUCT ON STG_GUARANTEES.v_prod_code = DIM_PRODUCT.v_prod_code AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_PRODUCT.D_RECORD_START_DATE AND DIM_PRODUCT.D_RECORD_END_DATE LEFT OUTER JOIN DIM_LOB ON STG_GUARANTEES.v_lob_code = DIM_LOB.v_lob_code AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_LOB.D_RECORD_START_DATE AND DIM_LOB.D_RECORD_END_DATE LEFT OUTER JOIN DIM_GAAP ON STG_GUARANTEES.v_gaap_code = DIM_GAAP.v_gaap_code AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_GAAP.D_RECORD_START_DATE AND DIM_GAAP.D_RECORD_END_DATE LEFT OUTER JOIN DIM_GEOGRAPHY ON coalesce(DIM_PARTY.V_BRANCH_CODE, 'MSG') = DIM_GEOGRAPHY.V_ACCT_BRANCH_CODE AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_GEOGRAPHY.D_RECORD_START_DATE AND DIM_GEOGRAPHY.D_RECORD_END_DATE LEFT OUTER JOIN DIM_INDUSTRY ON DIM_INDUSTRY.V_D_CUST_INDUSTRY = coalesce(DIM_PARTY.V_INDUSTRY_CODE, 'MSG') AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_INDUSTRY.D_RECORD_START_DATE AND DIM_INDUSTRY.D_RECORD_END_DATE LEFT OUTER JOIN SEC_POOL_MASTER ON STG_GUARANTEES.v_sec_pool_id = SEC_POOL_MASTER.v_sec_pool_id AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN SEC_POOL_MASTER.D_RECORD_START_DATE AND SEC_POOL_MASTER.D_RECORD_END_DATE LEFT OUTER JOIN DIM_EXPOSURE_UNDERLYING_TYPE ON STG_GUARANTEES.v_underlying_type_code = DIM_EXPOSURE_UNDERLYING_TYPE.v_underlying_type_code AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_EXPOSURE_UNDERLYING_TYPE.D_RECORD_START_DATE AND DIM_EXPOSURE_UNDERLYING_TYPE.D_RECORD_END_DATE INNER JOIN FCT_ENTITY_INFO ON STG_GUARANTEES.v_lv_code = FCT_ENTITY_INFO.v_entity_code INNER JOIN DIM_BASEL_CAP_CONSL_APPR ON DIM_BASEL_CAP_CONSL_APPR.n_basel_cap_consl_appr_skey = FCT_ENTITY_INFO.n_basel_cap_consl_appr_skey LEFT OUTER JOIN DIM_ISSUE ON STG_GUARANTEES.V_CONTRACT_CODE = DIM_ISSUE.v_issue_code AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_ISSUE.D_RECORD_START_DATE AND DIM_ISSUE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_PARTY_FINANCIALS ON FSI_CAP_PARTY_FINANCIALS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_CAP_PARTY_FINANCIALS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_CAP_PARTY_FINANCIALS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY LEFT OUTER JOIN ( RUN_EXE_PARAMETERS INNER JOIN DIM_RUN ON DIM_RUN.N_RUN_SKEY = RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_RUN.N_RUN_SKEY = '870' INNER JOIN DIM_ORG_STRUCTURE ON DIM_ORG_STRUCTURE.V_ENTITY_CODE = RUN_EXE_PARAMETERS.V_PARAM_VALUE_CODE AND to_date('20260331','YYYYMMDD') BETWEEN DIM_ORG_STRUCTURE.D_RECORD_START_DATE AND DIM_ORG_STRUCTURE.D_RECORD_END_DATE AND RUN_EXE_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY ) ON RUN_EXE_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS.V_PARAM_ID = 'LE' LEFT OUTER JOIN RUN_EXE_PARAMETERS RUN_EXE_PARAMETERS_RCY ON RUN_EXE_PARAMETERS_RCY.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND RUN_EXE_PARAMETERS_RCY.V_PARAM_ID = 'RCY' LEFT OUTER JOIN DIM_LOCATION ON DIM_LOCATION.V_LOCATION_CODE = DIM_PARTY.V_LOCATION_CODE AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_LOCATION.D_RECORD_START_DATE AND DIM_LOCATION.D_RECORD_END_DATE LEFT OUTER JOIN DIM_ACCOUNT_PURPOSE ON DIM_ACCOUNT_PURPOSE.V_ACCOUNT_PURPOSE_CODE = STG_GUARANTEES.V_CONTRACT_PURPOSE_CODE AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_ACCOUNT_PURPOSE.D_RECORD_START_DATE AND DIM_ACCOUNT_PURPOSE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_ACCOUNT_PURPOSE_RECLASS ON DIM_ACCOUNT_PURPOSE.N_ACCOUNT_PURPOSE_SKEY = FSI_ACCOUNT_PURPOSE_RECLASS.N_ACCOUNT_PURPOSE_SKEY AND FSI_ACCOUNT_PURPOSE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_ACCOUNT_PURPOSE_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY LEFT OUTER JOIN DIM_BUSINESS_UNIT ON STG_GUARANTEES.V_BUSINESS_UNIT_CODE = DIM_BUSINESS_UNIT.V_BUSINESS_UNIT_CODE LEFT OUTER JOIN FSI_REG_PROD_TYPE_RECLASS ON FSI_REG_PROD_TYPE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_REG_PROD_TYPE_RECLASS.N_RUN_SKEY = '870' AND FSI_REG_PROD_TYPE_RECLASS.N_PROD_SKEY = DIM_PRODUCT.N_PROD_SKEY LEFT OUTER JOIN FSI_PARTY_TYPE_CLASSIFICATION ON FSI_PARTY_TYPE_CLASSIFICATION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_TYPE_CLASSIFICATION.N_RUN_SKEY = '870' AND FSI_PARTY_TYPE_CLASSIFICATION.N_PARTY_TYPE_SKEY = DIM_PARTY_TYPE.N_PARTY_TYPE_SKEY LEFT OUTER JOIN DIM_CREDIT_LINE ON STG_GUARANTEES.V_LINE_CODE = DIM_CREDIT_LINE.V_CREDIT_LINE_CODE AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_CREDIT_LINE.D_RECORD_START_DATE AND DIM_CREDIT_LINE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION ON FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = STG_GUARANTEES.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION A_FSI_CAP_CURRENCY_CONVERSION ON A_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = A_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND A_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_CCY_CODE LEFT OUTER JOIN FSI_CAP_CURRENCY_CONVERSION B_FSI_CAP_CURRENCY_CONVERSION ON B_FSI_CAP_CURRENCY_CONVERSION.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND DIM_RUN.N_RUN_SKEY = B_FSI_CAP_CURRENCY_CONVERSION.N_RUN_SKEY AND B_FSI_CAP_CURRENCY_CONVERSION.V_CCY_CODE = FSI_CAP_PARTY_FINANCIALS.V_GROUP_CCY_CODE LEFT OUTER JOIN FSI_ACCT_MODELING_INFO ON FSI_ACCT_MODELING_INFO.V_EXPOSURE_ID = DIM_EXPOSURE.V_EXPOSURE_ID AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN FSI_ACCT_MODELING_INFO.D_RECORD_START_DATE AND FSI_ACCT_MODELING_INFO.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_RUN_EXE_PARAMETERS ON DIM_RUN.N_RUN_SKEY = FSI_CAP_RUN_EXE_PARAMETERS.N_RUN_SKEY AND DIM_DATES.n_date_skey = FSI_CAP_RUN_EXE_PARAMETERS.N_MIS_DATE_SKEY LEFT OUTER JOIN FSI_BASEL_EXEC_APPR_DETAILS ON FSI_BASEL_EXEC_APPR_DETAILS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.V_RISK_SUB_TYPE = 'NONSEC' AND FSI_CAP_RUN_EXE_PARAMETERS.F_PORTFOLIO_BASED_FLAG = 'N' LEFT OUTER JOIN RUN_PARAMETERS ON RUN_PARAMETERS.N_MIS_DATE_SKEY = DIM_DATES.n_date_skey AND RUN_PARAMETERS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_BASEL_EXEC_APPR_DETAILS.N_RUN_PARAMETER_SKEY = RUN_PARAMETERS.N_RUN_PARAMETER_SKEY LEFT OUTER JOIN DIM_COUNTRY ON STG_GUARANTEES.V_COUNTRY_CODE = DIM_COUNTRY.V_COUNTRY_ID AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_COUNTRY.D_RECORD_START_DATE AND DIM_COUNTRY.D_RECORD_END_DATE LEFT OUTER JOIN FSI_CAP_APPROACH_TYPE_MASTER ON FSI_CAP_APPROACH_TYPE_MASTER.V_APPROACH_TYPE = FSI_BASEL_EXEC_APPR_DETAILS.V_APPROACH_TYPE_CODE LEFT OUTER JOIN FSI_CAP_RECORD_TYPE_MASTER ON FSI_CAP_RECORD_TYPE_MASTER.V_RECORD_TYPE = 'BNK_NON_SEC_EXP' LEFT OUTER JOIN DIM_REPAYMENT_TYPE ON DIM_REPAYMENT_TYPE.V_REPAYMENT_TYPE = STG_GUARANTEES.V_REPAYMENT_TYPE AND STG_GUARANTEES.FIC_MIS_DATE BETWEEN DIM_REPAYMENT_TYPE.D_RECORD_START_DATE AND DIM_REPAYMENT_TYPE.D_RECORD_END_DATE LEFT OUTER JOIN FSI_PARTY_GRADE_RECLASS ON FSI_PARTY_GRADE_RECLASS.N_PARTY_SKEY = DIM_PARTY.N_PARTY_SKEY AND FSI_PARTY_GRADE_RECLASS.N_RUN_SKEY = DIM_RUN.N_RUN_SKEY AND FSI_PARTY_GRADE_RECLASS.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND FSI_PARTY_GRADE_RECLASS.N_STANDARD_PARTY_TYPE_SKEY = FSI_PARTY_TYPE_CLASSIFICATION.N_STANDARD_PARTY_TYPE_SKEY LEFT OUTER JOIN FCT_ENTITY_INFO FCT_ENTITY_INFO_CUST ON FCT_ENTITY_INFO.v_party_id = STG_GUARANTEES.v_cust_ref_code LEFT OUTER JOIN DIM_BASEL_CAP_CONSL_APPR DIM_BASEL_CAP_CONSL_APPR_CUST ON DIM_BASEL_CAP_CONSL_APPR_CUST.n_basel_cap_consl_appr_skey = FCT_ENTITY_INFO.n_basel_cap_consl_appr_skey AND FCT_ENTITY_INFO.n_mis_date_skey = DIM_DATES.n_date_skey AND FCT_ENTITY_INFO.n_run_skey = '870' AND FCT_ENTITY_INFO.f_cap_consl_entity_ind = 'Y' AND DIM_BASEL_CAP_CONSL_APPR_CUST.v_basel_cap_consl_appr_code IN ( 'FLCS' ,'PRCS' ,'FAGR' ,'PRAGR' ) WHERE 1=1 AND STG_GUARANTEES.FIC_MIS_DATE = to_date('20260331','YYYYMMDD') AND COALESCE(FCT_ENTITY_INFO.F_CAP_CONSL_ENTITY_IND, 'N') = 'Y' AND DIM_BASEL_CAP_CONSL_APPR.V_BASEL_CAP_CONSL_APPR_CODE IN ( 'FLCS' ,'PRCS' ) AND FCT_ENTITY_INFO.N_RUN_SKEY = '870' AND FCT_ENTITY_INFO.N_MIS_DATE_SKEY = DIM_DATES.N_DATE_SKEY AND STG_GUARANTEES.V_SEC_POOL_ID IS NULL AND COALESCE(STG_GUARANTEES.F_SECURITIZED_FLAG, 'N') <> 'Y' AND COALESCE(STG_GUARANTEES.F_ACCT_CLOSED_IND, 'N') <> 'Y' AND EXISTS ( SELECT 1 FROM FSI_CAP_ACCOUNT_LOAD_RUN_MAP WHERE FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_ACCOUNT_NUMBER  = DIM_EXPOSURE.V_EXPOSURE_ID AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.FIC_MIS_DATE = DIM_DATES.D_CALENDAR_DATE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.V_GAAP_CODE = DIM_GAAP.V_GAAP_CODE AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_RUN_SKEY = '870' AND FSI_CAP_ACCOUNT_LOAD_RUN_MAP.N_LOAD_RUN_ID = STG_GUARANTEES.N_LOAD_RUN_ID) AND STG_GUARANTEES.V_DATA_JURISDICTION='BASEL' LOG ERRORS INTO FSI_CAP_BANKING_EXPOSURES$ ('1776768367485_34720839_20260331_1_Job_49557914cc1b43fbab5904b7e0209ab6') REJECT LIMIT UNLIMITED;

    COMMIT;
    RETURN 'OK';

EXCEPTION
